export function calculateEmbedding(text: string): Vector {
  const normalized = normalizeText(text);
  return embeddingModel.encode(normalized);
}

class EmbeddingCache {
  private cache: Map<string, Vector>;

  constructor(maxSize: number) {
    this.cache = new LRUCache(maxSize);
  }

  get(key: string): Vector | null {
    return this.cache.get(key) || null;
  }

  set(key: string, value: Vector): void {
    this.cache.set(key, value);
  }
}

pub async fn embed_text(text: &str) -> Result<Vector, Error> {
    let cached = cache.get(text).await;
    if let Some(embedding) = cached {
        return Ok(embedding);
    }

    let embedding = client.embed(text).await?;
    cache.put(text, embedding.clone()).await?;
    Ok(embedding)
}

async function batchEmbed(texts: string[]): Promise<Vector[]> {
  const batchSize = 100;
  const results: Vector[] = [];

  for (let i = 0; i < texts.length; i += batchSize) {
    const batch = texts.slice(i, i + batchSize);
    const embeddings = await client.embedBatch(batch);
    results.push(...embeddings);
  }

  return results;
}

function calculateCosineDistance(a: Vector, b: Vector): number {
  const dotProduct = a.reduce((sum, val, i) => sum + val * b[i], 0);
  const magnitudeA = Math.sqrt(a.reduce((sum, val) => sum + val * val, 0));
  const magnitudeB = Math.sqrt(b.reduce((sum, val) => sum + val * val, 0));
  return 1 - (dotProduct / (magnitudeA * magnitudeB));
}

pub struct CostTracker {
    total_tokens: AtomicU64,
    total_requests: AtomicU64,
}

impl CostTracker {
    pub fn record_usage(&self, tokens: u64) {
        self.total_tokens.fetch_add(tokens, Ordering::Relaxed);
        self.total_requests.fetch_add(1, Ordering::Relaxed);
    }

    pub fn estimated_cost_usd(&self) -> f64 {
        let tokens = self.total_tokens.load(Ordering::Relaxed);
        (tokens as f64 / 1_000_000.0) * 0.02
    }
}

export async function retryWithBackoff<T>(
  fn: () => Promise<T>,
  maxAttempts: number = 3
): Promise<T> {
  let lastError: Error;

  for (let attempt = 0; attempt < maxAttempts; attempt++) {
    try {
      return await fn();
    } catch (error) {
      lastError = error as Error;
      if (attempt < maxAttempts - 1) {
        const delay = Math.pow(2, attempt) * 1000;
        await sleep(delay);
      }
    }
  }

  throw lastError!;
}

pub async fn generate_embeddings_batch(
    texts: Vec<String>,
    batch_size: usize,
) -> Result<Vec<Vector>, Error> {
    let mut all_embeddings = Vec::new();

    for chunk in texts.chunks(batch_size) {
        let embeddings = client.embed_batch(chunk.to_vec()).await?;
        all_embeddings.extend(embeddings);
        tokio::time::sleep(Duration::from_millis(100)).await;
    }

    Ok(all_embeddings)
}

